const body = $input.item.json.body || $input.item.json;

const executionId = 'mcp-' + Date.now().toString(36);
const timestamp = new Date().toISOString();

return [{ json: {
  ssh: {
    host: 'localhost',
    port: 2222,
    username: 'dju',
    password: 'S@alakazu17'
  },
  command: body.command || 'echo "No command provided"',
  executionId,
  timestamp,
  outputDir: '/tmp/mcp-results'
} }];

const item = $input.item.json;
const endTime = new Date();
const startTime = new Date(item.timestamp || Date.now());
const executionTime = endTime - startTime;

const success = !item.error;
const output = item.data || item.response || '';
const executionId = item.executionId;

// Create text report
const lines = [];
lines.push('═══════════════════════════════════════════════════════════════════════════════');
lines.push('                        MCP COMMAND EXECUTION REPORT');
lines.push('═══════════════════════════════════════════════════════════════════════════════');
lines.push('');
lines.push(`  Execution ID  : ${executionId}`);
lines.push(`  Timestamp    : ${endTime.toLocaleString()}`);
lines.push(`  Status       : ${success ? '✅ SUCCESS' : '❌ FAILED'}`);
lines.push(`  Duration     : ${executionTime}ms`);
lines.push('');
lines.push('───────────────────────────────────────────────────────────────────────────────');
lines.push('                              COMMAND');
lines.push('───────────────────────────────────────────────────────────────────────────────');
lines.push('');
lines.push(`  ${item.command || 'N/A'}`);
lines.push('');
lines.push('───────────────────────────────────────────────────────────────────────────────');
lines.push('                                OUTPUT');
lines.push('───────────────────────────────────────────────────────────────────────────────');
lines.push('');

if (!success) {
  lines.push(`  ❌ ERROR: ${item.error || 'Unknown error'}`);
} else if (output) {
  const outputLines = output.split('\n');
  outputLines.forEach(line => lines.push(`  ${line}`));
} else {
  lines.push('  (No output)');
}

lines.push('');
lines.push('═══════════════════════════════════════════════════════════════════════════════');

const reportText = lines.join('\n');

// Return data for saving to file
return [{ json: {
  success,
  executionId,
  server: 'localhost:2222',
  tool: 'ssh-execute',
  command: item.command,
  output,
  error: item.error || null,
  executionTime,
  timestamp: endTime.toISOString(),
  reportText,
  filePath: `/tmp/mcp-results/${executionId}.txt`
} }];

const item = $input.item.json;

// Build the text file content
const content = item.reportText;

return [{ json: {
  fileName: `${item.executionId}.txt`,
  fileContent: content,
  executionId: item.executionId,
  success: item.success,
  command: item.command,
  output: item.output,
  error: item.error,
  executionTime: item.executionTime,
  timestamp: item.timestamp
} }];
